=You are an AI Travel Booking Agent for a corporate travel system. 

You have received the following booking request:

Booking Reference: {{$json.bookingReference}}
Trip ID: {{$json.tripId}}

Flight Details:
- Flight: {{$json.flightDetails.flightId}} ({{$json.flightDetails.airline}})
- Route: {{$json.flightDetails.from}} → {{$json.flightDetails.to}}
- Date: {{$json.flightDetails.date}}
- Departure: {{$json.flightDetails.departureTime}}
- Price per ticket: {{$json.flightDetails.price}} {{$json.currency}}

Passengers: {{$json.totalPassengers}} travelers
Total Cost: {{$json.totalPrice}} {{$json.currency}}
Payment: {{$json.paymentMethod}}

Your task:
1. Confirm this booking is valid and complete
2. Generate a professional booking confirmation message
3. List any important travel information or reminders
4. Respond in JSON format with these fields:
   - status: "confirmed" or "error"
   - bookingId: the booking reference
   - confirmationMessage: a friendly confirmation paragraph
   - importantInfo: array of key travel reminders
   - nextSteps: what passengers should do next

Be professional, helpful, and concise.

parameters.jsCode:
// Get raw input from previous node (Webhook)
const incoming = $input.first().json;

// Support both shapes: with body{} or directly
const bookingRequest = incoming.body ?? incoming;

// Basic safety defaults
const flight = bookingRequest.selectedFlight || {};
const passengers = bookingRequest.passengers || [];

// Generate unique booking reference
const bookingRef = `BK${Date.now().toString().slice(-8)}`;

// Make sure price is a number
const pricePerPassenger = Number(flight.price ?? 0);

// Total price = price * number of passengers
const totalPrice = pricePerPassenger * passengers.length;

// Return structured booking object
return {
  json: {
    bookingReference: bookingRef,
    tripId: bookingRequest.tripId,
    flightDetails: flight,
    passengers: passengers,
    totalPassengers: passengers.length,
    totalPrice: totalPrice,
    currency: "SAR",
    paymentMethod: bookingRequest.paymentMethod,
    bookingTimestamp: new Date().toISOString()
  }
};

// 1) Read booking context safely
const bookingItems = $items('Structure data for AI Agent');

if (!bookingItems || bookingItems.length === 0) {
	throw new Error("Booking context node returned NO data");
}

const bookingContext = bookingItems[0].json;

// 2) Read AI output safely
const inputItems = $input.all();

if (!inputItems || inputItems.length === 0) {
	throw new Error("AI node returned NO data");
}

const llmOutput = inputItems[0].json;

// 3) Extract raw text safely
let rawJson = '';

if (typeof llmOutput === 'string') {
	rawJson = llmOutput;
}
else if (llmOutput.text) {
	rawJson = llmOutput.text;
}
else if (llmOutput.output?.[0]?.content?.[0]?.text) {
	rawJson = llmOutput.output[0].content[0].text;
}
else {
	throw new Error("AI response format NOT recognized");
}

// 4) Clean JSON safely
rawJson = rawJson
	.replace(/```json/g, '')
	.replace(/```/g, '')
	.trim()
	.replace(/,\s*}/g, '}')
	.replace(/,\s*]/g, ']');

// 5) Parse AI JSON
let aiResponse;
try {
	aiResponse = JSON.parse(rawJson);
} catch (err) {
	throw new Error("AI returned INVALID JSON: " + rawJson);
}

// 6) Build final confirmation safely
const result = {
	success: true,
	tripId: bookingContext.tripId || null,
	bookingReference: bookingContext.bookingReference || null,
	bookingTimestamp: bookingContext.bookingTimestamp || new Date().toISOString(),

	flightDetails: {
		flightId: bookingContext.flightDetails?.flightId || null,
		airline: bookingContext.flightDetails?.airline || null,
		route: `${bookingContext.flightDetails?.from || "?"} → ${bookingContext.flightDetails?.to || "?"}`,
		date: bookingContext.flightDetails?.date || null,
		departureTime: bookingContext.flightDetails?.departureTime || null,
	},

	passengers: bookingContext.passengers || [],

	pricing: {
		pricePerTicket: bookingContext.flightDetails?.price || 0,
		totalPassengers: bookingContext.totalPassengers || 0,
		totalCost: bookingContext.totalPrice || 0,
		currency: bookingContext.currency || "SAR",
	},

	aiConfirmation: {
		status: aiResponse.status || "confirmed",
		message: aiResponse.confirmationMessage || "",
		importantInfo: aiResponse.importantInfo || "",
		nextSteps: aiResponse.nextSteps || "",
	},

	tickets: (bookingContext.passengers || []).map((p, index) => ({
		ticketNumber: `${bookingContext.bookingReference || "BK"}-${index + 1}`,
		passengerName: p.name || "Unknown",
		email: p.email || "",
	}))
};

// 7) Return final output
return [{ json: result }];
